ROOT="E:/PORTFOLIO/portfolio-build/public/work"

for slug in "${!IDS[@]}"; do
  mkdir -p "$ROOT/$slug"
  i=1
  for id in ${IDS[$slug]}; do
    out="$ROOT/$slug/gallery-$i.jpg"
    if [ ! -s "$out" ]; then
      curl -s -L --max-time 25 -o "$out" "https://images.unsplash.com/photo-$id?w=900&q=80&auto=format&fit=crop" &
